import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"月坛公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/yuetan-park.md","filePath":"parks/yuetan-park.md","lastUpdated":null}'),n={name:"parks/yuetan-park.md"};function d(o,t,i,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="月坛公园" tabindex="-1">月坛公园 <a class="header-anchor" href="#月坛公园" aria-label="Permalink to &quot;月坛公园&quot;">​</a></h1><blockquote><p>&quot;明清祭月之所，西城区的小众公园。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>月坛公园位于北京市西城区，是明清两代皇帝祭祀月神的地方。月坛始建于明嘉靖九年（1530年），与天坛、地坛、日坛、先农坛并列为明清五坛之一。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">1元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">秋季赏月</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线阜成门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区月坛北街6号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>明嘉靖九年（1530年），明世宗朱厚熜决定实行天地分祀，在北京西郊建月坛，专祀月神（夜明之神）。</p><h3 id="清代修缮" tabindex="-1">清代修缮 <a class="header-anchor" href="#清代修缮" aria-label="Permalink to &quot;清代修缮&quot;">​</a></h3><p>清代，月坛多次修缮，规模不断扩大。</p><h3 id="现代公园" tabindex="-1">现代公园 <a class="header-anchor" href="#现代公园" aria-label="Permalink to &quot;现代公园&quot;">​</a></h3><p>1950年代，月坛辟为公园，对外开放。现为月坛公园。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="月坛" tabindex="-1">月坛 <a class="header-anchor" href="#月坛" aria-label="Permalink to &quot;月坛&quot;">​</a></h3><p>月坛是公园的核心建筑，是明清皇帝祭祀月神的地方。</p><h4 id="布局" tabindex="-1">布局 <a class="header-anchor" href="#布局" aria-label="Permalink to &quot;布局&quot;">​</a></h4><ul><li><strong>坛台</strong>：方形，一层</li><li><strong>坛墙</strong>：方形，四面</li><li><strong>棂星门</strong>：坛南的正门</li></ul><h3 id="具服殿" tabindex="-1">具服殿 <a class="header-anchor" href="#具服殿" aria-label="Permalink to &quot;具服殿&quot;">​</a></h3><p>具服殿是皇帝更衣的地方。</p><h3 id="神厨" tabindex="-1">神厨 <a class="header-anchor" href="#神厨" aria-label="Permalink to &quot;神厨&quot;">​</a></h3><p>神厨是制作祭祀食品的地方。</p><h2 id="赏月" tabindex="-1">赏月 <a class="header-anchor" href="#赏月" aria-label="Permalink to &quot;赏月&quot;">​</a></h2><p>月坛是明清皇帝祭月的地方，也是赏月的好地方。</p><h3 id="中秋赏月" tabindex="-1">中秋赏月 <a class="header-anchor" href="#中秋赏月" aria-label="Permalink to &quot;中秋赏月&quot;">​</a></h3><p>每年中秋节，月坛是赏月的传统地点。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>月坛游览（约1小时）</strong>：</p><p>南门 → 月坛 → 具服殿 → 神厨 → 北门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线阜成门站D口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">3路、13路、42路等月坛公园站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从金融街步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票便宜</strong>：门票仅1元</li><li><strong>人少清静</strong>：游客较少，比较清静</li><li><strong>中秋赏月</strong>：中秋赏月的好地方</li><li><strong>结合游览</strong>：可与金融街、阜成门一起游览</li><li><strong>跑步好地方</strong>：适合跑步、散步</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">金融街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">金融中心</td></tr><tr><td style="text-align:left;">阜成门</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老城门</td></tr><tr><td style="text-align:left;">白塔寺</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">藏传佛教寺院</td></tr><tr><td style="text-align:left;">鲁迅故居</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">鲁迅故居</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>月坛是明清五坛之一，是中国古代祭祀文化的重要遗存。</p><p>月坛与天坛、地坛、日坛、先农坛相对应，体现了中国古代&quot;天南地北，日东月西&quot;的宇宙观念。</p><hr><p><strong>📍 地址</strong>：北京市西城区月坛北街6号 <strong>📞 电话</strong>：010-68035062</p>',41)])])}const f=a(n,[["render",d]]);export{c as __pageData,f as default};
